[FormDesignPropertyAttribute("Filename")]
public str parmFileName(str _value = fileName)
{
    if(!prmisdefault(_value))
    {
        fileName = _value;
    }
    return fileName;
}

[FormDesignPropertyAttribute("User language")]
public str parmUserLanguage(str _value = userLanguage)
{
    if(!prmisdefault(_value))
